    {"path":"src/modules/tasks/routes.js","content":"import express from 'express';
import { createTask, getTasksByProjectId, updateTaskStatus } from './service.js';
import { sendError } from '../../lib/errors.js';

const router = express.Router({ mergeParams: true });

router.post('/', async (req, res) => {
  try {
    const task = createTask(req.body.title);
    res.status(201).json({ task });
  } catch (error) {
    if (error.message === 'Title is required') return sendError(res, 400, 'BadRequestError', error.message);
    throw error;
  }
});

router.get('/', async (req, res) => {
  const tasks = await getTasksByProjectId(req.params.projectId);
  if (!tasks || tasks.length === 0) return sendError(res, 404, 'NotFoundError', 'No tasks found');
  res.json({ tasks });
});

router.patch('/:taskId', async (req, res) => {
  const task = await updateTaskStatus(req.params.projectId, req.params.taskId, req.body.status);
  if (!task) return sendError(res, 404, 'NotFoundError', 'Task not found');
  if (['todo', 'done'].includes(req.body.status)) {
    res.json({ task });
  } else {
    return sendError(res, 400, 'BadRequestError', 'Invalid status');
  }
});

export default router;
"},
    {"path":"src/modules/tasks/service.js","content":"import { randomUUID } from 'node:crypto';
import { sendError } from '../../lib/errors.js';

const tasks = {};

export const createTask = (title) => {
  if (!title) throw new Error('Title is required');
  const id = randomUUID();
  tasks[id] = { id, title, status: 'todo' };
  return { id, title, status: 'todo' };
};

export const getTasksByProjectId = (projectId) => {
  return Object.values(tasks).filter(task => task.projectId === projectId);
};

export const updateTaskStatus = (projectId, taskId, status) => {
  if (!['todo', 'done'].includes(status)) throw new Error('Invalid status');
  tasks[taskId].status = status;
  return { id: taskId, title: tasks[taskId].title, status };
};
